def lengthOfLongestSubstring(s):
    seen = {}
    left = 0
    best = 0
    for right, ch in enumerate(s):
        if ch in seen:
            left = seen[ch] + 1
        seen[ch] = right
        best = max(best, right - left + 1)
    return best

def search(nums, target):
    lo, hi = 0, len(nums)-1
    while lo <= hi:
        mid = (lo + hi)//2
        if nums[mid] == target:
            return mid
        if nums[mid] < target:
            lo = mid + 1
        else:
            hi = mid - 1
    return -1

def merge(intervals):
    intervals.sort()
    ans = []
    for start, end in intervals:
        if not ans or ans[-1][1] < start:
            ans.append([start, end])
        else:
            ans[-1][1] = max(ans[-1][1], end)
    return ans
